// AXIOM Proposal Generator
// Generates AI-powered sales proposals for qualified leads

const leads = $input.all();

const proposals = leads.map(lead => {
  return {
    json: {
      leadName: lead.json.name || 'Prospect',
      businessType: lead.json.businessType || 'Business',
      proposal: `Dear ${lead.json.name || 'Valued Prospect'},\n\nThank you for your interest in Digital Plug Co. Based on your needs, we recommend our AXIOM automation package.\n\nProposal ID: DPC-${Date.now()}\nDate: ${new Date().toLocaleDateString()}\n\nNext Steps: Reply YES to schedule your onboarding call.\n\n- Digital Plug Co. Team`,
      createdAt: new Date().toISOString()
    }
  };
});

return proposals.length > 0 ? proposals : [{ json: { status: 'No leads to process', timestamp: new Date().toISOString() } }];
